<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    --bg: #14161c;
    --panel: #1d212b;
    --border: #2c3140;
    --accent: #5b8dee;
    --text: #d7dbe6;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
    padding: 24px;
  }
  h1 {
    font-size: 18px;
    font-weight: 600;
    letter-spacing: 0.02em;
    color: var(--text);
    margin: 0;
  }
  #panel {
    display: flex;
    gap: 8px;
    flex-wrap: wrap;
    justify-content: center;
    background: var(--panel);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 10px;
  }
  button.mat {
    display: flex;
    align-items: center;
    gap: 8px;
    background: #262b38;
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 8px 14px;
    font-size: 13px;
    cursor: pointer;
    transition: transform 0.08s ease, border-color 0.15s ease, background 0.15s ease;
  }
  button.mat:hover { background: #2f3547; }
  button.mat:active { transform: scale(0.96); }
  button.mat.selected {
    border-color: var(--accent);
    background: #2a3550;
    box-shadow: 0 0 0 1px var(--accent) inset;
  }
  .swatch {
    width: 12px;
    height: 12px;
    border-radius: 3px;
    display: inline-block;
    border: 1px solid rgba(255,255,255,0.15);
  }
  #clear {
    background: #40222a;
    color: #ffb4c0;
    border: 1px solid #6b2f3a;
    border-radius: 8px;
    padding: 8px 16px;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s ease, transform 0.08s ease;
  }
  #clear:hover { background: #522a34; }
  #clear:active { transform: scale(0.96); }
  #canvas-wrap {
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 10px;
    background: var(--panel);
    box-shadow: 0 10px 30px rgba(0,0,0,0.4);
  }
  #sand {
    display: block;
    border-radius: 6px;
    cursor: crosshair;
    image-rendering: pixelated;
    background: #0a0b0f;
  }
  #hint {
    font-size: 12px;
    color: #7f8696;
  }
</style>
</head>
<body>
  <h1>Falling Sand Sandbox</h1>
  <div id="panel">
    <button class="mat selected" id="mat-sand" data-mat="sand"><span class="swatch" style="background:#d9b35c"></span>Sand</button>
    <button class="mat" id="mat-water" data-mat="water"><span class="swatch" style="background:#3f8fdb"></span>Water</button>
    <button class="mat" id="mat-wall" data-mat="wall"><span class="swatch" style="background:#7d818c"></span>Wall</button>
    <button class="mat" id="mat-acid" data-mat="acid"><span class="swatch" style="background:#69d46a"></span>Acid</button>
    <button class="mat" id="mat-empty" data-mat="empty"><span class="swatch" style="background:#0a0b0f"></span>Eraser</button>
    <button id="clear">Clear</button>
  </div>
  <div id="canvas-wrap">
    <canvas id="sand" width="500" height="500"></canvas>
  </div>
  <div id="hint">Click and drag on the canvas to paint. Pick a material above.</div>

<script>
(function () {
  "use strict";

  // ---------- Grid setup ----------
  const W = 100, H = 100;      // cells (>= 80x80)
  const CELL = 5;              // px per cell -> 500x500 canvas (>= 400x400)

  const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;

  const NAME_TO_CODE = { empty: EMPTY, sand: SAND, water: WATER, wall: WALL, acid: ACID };
  const CODE_TO_NAME = ["empty", "sand", "water", "wall", "acid"];
  const CODE_TO_COLOR = ["#0a0b0f", "#d9b35c", "#3f8fdb", "#7d818c", "#69d46a"];

  let grid = new Uint8Array(W * H);

  function idx(x, y) { return y * W + x; }
  function inBounds(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }

  function swap(i, j) {
    const t = grid[i];
    grid[i] = grid[j];
    grid[j] = t;
  }

  // ---------- Simulation step ----------
  function tryMoveDown(x, y, moved, targets) {
    const i = idx(x, y);
    if (y + 1 >= H) return false; // bottom row is a solid boundary
    const below = idx(x, y + 1);
    if (targets.indexOf(grid[below]) !== -1) {
      swap(i, below);
      moved[i] = 1; moved[below] = 1;
      return true;
    }
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx;
      if (nx < 0 || nx >= W) continue; // side edges are solid boundaries
      const dIdx = idx(nx, y + 1);
      if (targets.indexOf(grid[dIdx]) !== -1) {
        swap(i, dIdx);
        moved[i] = 1; moved[dIdx] = 1;
        return true;
      }
    }
    return false;
  }

  function trySpread(x, y, moved) {
    const i = idx(x, y);
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx;
      if (nx < 0 || nx >= W) continue;
      const nIdx = idx(nx, y);
      if (grid[nIdx] === EMPTY) {
        swap(i, nIdx);
        moved[i] = 1; moved[nIdx] = 1;
        return true;
      }
    }
    return false;
  }

  function updateSand(x, y, moved) {
    tryMoveDown(x, y, moved, [EMPTY, WATER, ACID]);
  }

  function updateWater(x, y, moved) {
    if (tryMoveDown(x, y, moved, [EMPTY])) return;
    trySpread(x, y, moved);
  }

  function updateAcid(x, y, moved) {
    const i = idx(x, y);
    const targets = [];
    if (y + 1 < H) targets.push(idx(x, y + 1));
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx;
      if (nx >= 0 && nx < W) targets.push(idx(nx, y));
    }
    for (const tIdx of targets) {
      const tM = grid[tIdx];
      if (tM === SAND || tM === WALL) {
        grid[tIdx] = EMPTY;
        moved[tIdx] = 1;
        if (Math.random() < 0.35) {
          grid[i] = EMPTY;
          moved[i] = 1;
        }
        return;
      }
    }
    if (tryMoveDown(x, y, moved, [EMPTY])) return;
    trySpread(x, y, moved);
  }

  function step() {
    const moved = new Uint8Array(W * H);
    for (let y = H - 1; y >= 0; y--) {
      // randomize x order per row to avoid directional bias
      const xs = new Array(W);
      for (let k = 0; k < W; k++) xs[k] = k;
      for (let k = W - 1; k > 0; k--) {
        const r = Math.floor(Math.random() * (k + 1));
        const tmp = xs[k]; xs[k] = xs[r]; xs[r] = tmp;
      }
      for (const x of xs) {
        const i = idx(x, y);
        if (moved[i]) continue;
        const m = grid[i];
        if (m === EMPTY || m === WALL) continue;
        if (m === SAND) updateSand(x, y, moved);
        else if (m === WATER) updateWater(x, y, moved);
        else if (m === ACID) updateAcid(x, y, moved);
      }
    }
  }

  // ---------- Rendering ----------
  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d");

  function render() {
    ctx.fillStyle = CODE_TO_COLOR[EMPTY];
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const m = grid[idx(x, y)];
        if (m === EMPTY) continue;
        ctx.fillStyle = CODE_TO_COLOR[m];
        ctx.fillRect(x * CELL, y * CELL, CELL, CELL);
      }
    }
  }

  // ---------- Public API ----------
  window.sim = {
    w: W,
    h: H,
    tick(n) {
      n = n || 1;
      for (let k = 0; k < n; k++) step();
    },
    get(x, y) {
      if (!inBounds(x, y)) return "empty";
      return CODE_TO_NAME[grid[idx(x, y)]];
    },
    set(x, y, material) {
      if (!inBounds(x, y)) return;
      const code = NAME_TO_CODE[material];
      if (code === undefined) return;
      grid[idx(x, y)] = code;
    },
    clear() {
      grid.fill(EMPTY);
    }
  };

  // ---------- UI wiring ----------
  let selectedMaterial = "sand";
  const matButtons = document.querySelectorAll("button.mat");
  matButtons.forEach((btn) => {
    btn.addEventListener("click", () => {
      selectedMaterial = btn.dataset.mat;
      matButtons.forEach((b) => b.classList.remove("selected"));
      btn.classList.add("selected");
    });
  });

  document.getElementById("clear").addEventListener("click", () => {
    window.sim.clear();
  });

  function cellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const px = (e.clientX - rect.left) * scaleX;
    const py = (e.clientY - rect.top) * scaleY;
    const x = Math.floor(px / CELL);
    const y = Math.floor(py / CELL);
    return { x, y };
  }

  let painting = false;
  const BRUSH_RADIUS = 1;

  function paintAt(x, y) {
    for (let dy = -BRUSH_RADIUS; dy <= BRUSH_RADIUS; dy++) {
      for (let dx = -BRUSH_RADIUS; dx <= BRUSH_RADIUS; dx++) {
        const nx = x + dx, ny = y + dy;
        if (inBounds(nx, ny)) {
          window.sim.set(nx, ny, selectedMaterial);
        }
      }
    }
  }

  function handlePaint(e) {
    const { x, y } = cellFromEvent(e);
    if (inBounds(x, y)) paintAt(x, y);
  }

  canvas.addEventListener("mousedown", (e) => {
    painting = true;
    handlePaint(e);
  });
  window.addEventListener("mouseup", () => { painting = false; });
  canvas.addEventListener("mousemove", (e) => {
    if (painting) handlePaint(e);
  });
  canvas.addEventListener("mouseleave", () => {
    // keep painting state; mouseup on window will stop it if released outside
  });

  // touch support
  canvas.addEventListener("touchstart", (e) => {
    painting = true;
    handlePaint(e.touches[0]);
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener("touchmove", (e) => {
    if (painting) handlePaint(e.touches[0]);
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener("touchend", () => { painting = false; });

  // ---------- Animation loop ----------
  function frame() {
    step();
    render();
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
